import { I18n } from './i18n';
/**
 * @ignore
 */
export interface Config {
    i18n?: I18n;
    branding: BrandingConfig;
    collapsible: boolean;
    active: boolean;
    label: string;
    host: Host;
    siteInfo: SiteInfo;
    umbrella: Umbrella;
    languageLinks: LanguageLink[];
    navigationLinks: NavigationLink[];
    extensions: {
        pluginTypeId: string;
        i18n?: I18n;
        [key: string]: string | number | object | undefined;
    }[];
}
/**
 * Represents the branding configuration, including color settings.
 */
export interface BrandingConfig {
    colors: {
        /**
         * The primary color used in the branding.
         */
        primary: string;
        /**
         * The functional color used for elements like buttons and links.
         */
        functional: string;
    };
}
/**
 * Represents an image-based host configuration.
 */
export interface ImageHost {
    /**
     * Specifies that this host type is an image.
     */
    type: 'image';
    /**
     * The alternative text for the image.
     */
    alt: string;
    /**
     * The source URL of the image.
     */
    src?: string | null;
    /**
     * An array of source URLs for different resolutions (optional).
     */
    srcSet?: string[] | null;
}
/**
 * Represents a text-based host configuration.
 */
export interface TextHost {
    /**
     * Specifies that this host type is text.
     */
    type: 'text';
    /**
     * The department name associated with the host.
     */
    department: string;
    /**
     * The site owner name associated with the host.
     */
    siteOwner: string;
}
/**
 * A union type that can either be `null`, an `ImageHost`, or a `TextHost`.
 * The host is shown on the top right of the footer.
 */
export type Host = null | ImageHost | TextHost;
/**
 * Represents a link displayed in the footer subtitle.
 */
export interface PublisherLink {
    /**
     * Specifies that this subtitle item is a link.
     */
    type: 'link';
    /**
     * The URL the link points to.
     */
    href: string;
    /**
     * The label for the link.
     */
    label: string;
    /**
     * The target where the link should be opened (optional).
     */
    target?: string;
}
/**
 * Represents a text displayed in the footer subtitle.
 */
export interface PublisherText {
    /**
     * Specifies that this subtitle item is text.
     */
    type: 'text';
    /**
     * The label for the text item.
     */
    label: string;
}
/**
 * A union type that can either be a link or a text item for subtitles.
 */
export type SubTitleItem = PublisherLink | PublisherText;
/**
 * Represents the site information, including the title and subtitle items.
 */
export interface SiteInfo {
    /**
     * The title of the site.
     */
    title: string;
    /**
     * An array of subtitle items (either links or text).
     */
    subTitleItems: SubTitleItem[];
}
/**
 * Represents the umbrella image configuration. This is shown on the left of the footer.
 */
export type Umbrella = null | {
    /**
     * The alternative text for the umbrella image.
     */
    alt: string;
    /**
     * The source URL of the umbrella image (optional).
     */
    src?: string | null;
    /**
     * An array of source URLs for different resolutions (optional).
     */
    srcSet?: string[] | null;
};
/**
 * Represents a language link for switching between language versions of the site.
 * These are shown on the bottom right of the footer
 */
export interface LanguageLink {
    /**
     * The URL of the language link.
     */
    href: string;
    /**
     * The label of the language link.
     */
    label: string;
    /**
     * The language code for the link (e.g., 'nl', 'fr', 'de', 'en').
     */
    langcode: 'nl' | 'fr' | 'de' | 'en';
    /**
     * The target where the link should be opened (optional).
     */
    target?: string;
}
/**
 * Represents a navigation link in the footer. These are shown on the bottom center of the footer.
 */
export interface NavigationLink {
    /**
     * The URL of the navigation link.
     */
    href: string;
    /**
     * The label of the navigation link.
     */
    label: string;
    /**
     * The target where the navigation link should be opened (optional).
     */
    target?: string;
}
